def solution(limit: int = 1000000) -> int:
    """
    Uses a modified sieve to calculate the sum of Euler's totient function more efficiently.
    Based on the property: sum_{d|n} phi(d) = n.
    """
    phi = list(range(limit + 1))
    total_sum = 0

    for i in range(2, limit + 1):
        if phi[i] == i:
            # Prime i found
            for j in range(i, limit + 1, i):
                phi[j] -= phi[j] // i
        total_sum += phi[i]

    return total_sum


